import heapq

class _Worst:
    __slots__ = ('key', 'name')

    def __init__(self, key, name):
        self.key = key
        self.name = name

    def __lt__(self, other):
        return self.key > other.key

    def __eq__(self, other):
        return self.key == other.key

class SORTracker:
    def __init__(self):
        self.top = []
        self.rest = []
        self.k = 0

    def add(self, name, score):
        key = (-score, name)
        if self.top and key < self.top[0].key:
            heapq.heappush(self.top, _Worst(key, name))
            worst = heapq.heappop(self.top)
            heapq.heappush(self.rest, (worst.key, worst.name))
        else:
            heapq.heappush(self.rest, (key, name))

    def get(self):
        self.k += 1
        while len(self.top) < self.k and self.rest:
            key, name = heapq.heappop(self.rest)
            heapq.heappush(self.top, _Worst(key, name))
        return self.top[0].name

