class Heap {
    constructor(cmp) {
        this.data = [];
        this.cmp = cmp;
    }
    get size() { return this.data.length; }
    peek() { return this.data[0]; }
    push(item) {
        this.data.push(item);
        let i = this.data.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (this.cmp(this.data[p], this.data[i]) <= 0) break;
            [this.data[p], this.data[i]] = [this.data[i], this.data[p]];
            i = p;
        }
    }
    pop() {
        const top = this.data[0];
        const last = this.data.pop();
        if (this.data.length > 0) {
            this.data[0] = last;
            let i = 0;
            const n = this.data.length;
            while (true) {
                let l = i * 2 + 1, r = i * 2 + 2, best = i;
                if (l < n && this.cmp(this.data[l], this.data[best]) < 0) best = l;
                if (r < n && this.cmp(this.data[r], this.data[best]) < 0) best = r;
                if (best === i) break;
                [this.data[i], this.data[best]] = [this.data[best], this.data[i]];
                i = best;
            }
        }
        return top;
    }
}

function cmpKey(a, b) {
    if (a[0] !== b[0]) return b[0] - a[0];
    if (a[1] < b[1]) return -1;
    if (a[1] > b[1]) return 1;
    return 0;
}

class SORTracker {
    constructor() {
        this.top = new Heap((a, b) => -cmpKey(a, b));
        this.rest = new Heap(cmpKey);
        this.k = 0;
    }

    add(name, score) {
        const item = [score, name];
        if (this.top.size > 0 && cmpKey(item, this.top.peek()) < 0) {
            this.top.push(item);
            const worst = this.top.pop();
            this.rest.push(worst);
        } else {
            this.rest.push(item);
        }
    }

    get() {
        this.k += 1;
        while (this.top.size < this.k && this.rest.size > 0) {
            this.top.push(this.rest.pop());
        }
        return this.top.peek()[1];
    }
}
